import React, { useState, useEffect, useRef } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import Nav from "./Nev";

// ─── CONFIG — sirf yeh 2 cheezein update karo ──────────────
const RAZORPAY_KEY_ID = "rzp_test_Sq7J7mRZo6zCD1"; // 🔴 Apni Razorpay key
const MERCHANT_UPI    = "petology@upi";              // 🔴 Apna UPI ID (e.g. 9876543210@okaxis)
const MERCHANT_NAME   = "Petology Pet Shop";
// ────────────────────────────────────────────────────────────

const UPI_APPS = [
  {
    id: "gpay", name: "Google Pay", color: "#4285F4", bg: "#e8f0fe", label: "G",
    labelStyle: { background: "linear-gradient(135deg,#4285F4,#34A853,#FBBC05,#EA4335)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent", fontWeight: 900, fontSize: 20 },
    getLink: (upi, amt, note) => `tez://upi/pay?pa=${upi}&pn=${encodeURIComponent(MERCHANT_NAME)}&am=${amt}&cu=INR&tn=${note}`,
  },
  {
    id: "phonepe", name: "PhonePe", color: "#5f259f", bg: "#f3e8ff", label: "Pe",
    labelStyle: { color: "#5f259f", fontWeight: 900, fontSize: 18 },
    getLink: (upi, amt, note) => `phonepe://pay?pa=${upi}&pn=${encodeURIComponent(MERCHANT_NAME)}&am=${amt}&cu=INR&tn=${note}`,
  },
  {
    id: "paytm", name: "Paytm", color: "#00BAF2", bg: "#e0f7fe", label: "PT",
    labelStyle: { color: "#00BAF2", fontWeight: 900, fontSize: 16 },
    getLink: (upi, amt, note) => `paytmmp://upi/pay?pa=${upi}&pn=${encodeURIComponent(MERCHANT_NAME)}&am=${amt}&cu=INR&tn=${note}`,
  },
  {
    id: "bhim", name: "BHIM UPI", color: "#e84141", bg: "#fee2e2", label: "B",
    labelStyle: { color: "#e84141", fontWeight: 900, fontSize: 20 },
    getLink: (upi, amt, note) => `upi://pay?pa=${upi}&pn=${encodeURIComponent(MERCHANT_NAME)}&am=${amt}&cu=INR&tn=${note}`,
  },
];

// ─── QR Code generator (pure canvas, no library needed) ─────
function UpiQR({ upiString, size = 220 }) {
  const canvasRef = useRef(null);
  const [loaded, setLoaded] = useState(false);

  useEffect(() => {
    // Load qrcode-generator from CDN and draw on canvas
    if (window.qrcode) { drawQR(); return; }
    const s = document.createElement("script");
    s.src = "https://cdnjs.cloudflare.com/ajax/libs/qrcodejs/1.0.0/qrcode.min.js";
    s.onload = drawQR;
    document.head.appendChild(s);
  }, [upiString]);

  function drawQR() {
    // Use a hidden div trick with QRCode lib
    const div = document.createElement("div");
    div.style.display = "none";
    document.body.appendChild(div);
    try {
      // eslint-disable-next-line no-undef
      new QRCode(div, {
        text: upiString,
        width: size,
        height: size,
        colorDark: "#1a1a2e",
        colorLight: "#ffffff",
        correctLevel: window.QRCode?.CorrectLevel?.H || 1,
      });
      setTimeout(() => {
        const img = div.querySelector("img");
        const canvas = canvasRef.current;
        if (!canvas || !img) return;
        const ctx = canvas.getContext("2d");
        const image = new Image();
        image.onload = () => {
          ctx.drawImage(image, 0, 0, size, size);
          setLoaded(true);
        };
        image.src = img.src;
        document.body.removeChild(div);
      }, 300);
    } catch (e) {
      document.body.removeChild(div);
    }
  }

  return (
    <div style={{ position: "relative", width: size, height: size }}>
      {!loaded && (
        <div style={{
          position: "absolute", inset: 0, display: "flex", flexDirection: "column",
          alignItems: "center", justifyContent: "center",
          background: "#fff", borderRadius: 12, gap: 8,
        }}>
          <div style={{ width: 32, height: 32, border: "3px solid #6366f1", borderTopColor: "transparent", borderRadius: "50%", animation: "spin 0.8s linear infinite" }} />
          <span style={{ fontSize: 11, color: "#6b7280" }}>Generating QR...</span>
        </div>
      )}
      <canvas
        ref={canvasRef}
        width={size}
        height={size}
        style={{ borderRadius: 12, display: loaded ? "block" : "none" }}
      />
    </div>
  );
}

// ─── Styles ──────────────────────────────────────────────────
const css = `
  @import url('https://fonts.googleapis.com/css2?family=Syne:wght@400;600;700;800&family=DM+Sans:wght@300;400;500;600&display=swap');

  .co-page{min-height:100vh;background:#08080f;font-family:'DM Sans',sans-serif;position:relative;overflow-x:hidden;}
  .co-bg{position:fixed;inset:0;z-index:0;pointer-events:none;
    background:radial-gradient(ellipse 80% 50% at 15% 15%,rgba(99,102,241,0.2) 0%,transparent 60%),
               radial-gradient(ellipse 60% 40% at 85% 80%,rgba(16,185,129,0.14) 0%,transparent 60%),#08080f;}
  .co-wrap{position:relative;z-index:1;max-width:500px;margin:0 auto;padding:16px 16px 80px;}

  .co-header{text-align:center;padding:28px 0 20px;}
  .co-logo{font-family:'Syne',sans-serif;font-size:12px;font-weight:700;letter-spacing:5px;color:#6366f1;text-transform:uppercase;margin-bottom:6px;}
  .co-title{font-family:'Syne',sans-serif;font-size:30px;font-weight:800;color:#fff;margin:0 0 6px;}
  .co-sub{font-size:12px;color:#4b5563;letter-spacing:1px;}

  .co-amount{background:linear-gradient(135deg,#131320 0%,#0f1729 100%);border:1px solid rgba(99,102,241,0.25);
    border-radius:20px;padding:26px;margin-bottom:14px;display:flex;justify-content:space-between;align-items:center;
    box-shadow:0 0 50px rgba(99,102,241,0.08),inset 0 1px 0 rgba(255,255,255,0.04);animation:slideUp 0.4s ease;}
  .co-amt-label{font-size:11px;letter-spacing:3px;text-transform:uppercase;color:#4b5563;margin-bottom:6px;}
  .co-amt-val{font-family:'Syne',sans-serif;font-size:40px;font-weight:800;color:#fff;line-height:1;}
  .co-amt-val em{font-style:normal;font-size:22px;color:#818cf8;}
  .co-amt-free{font-size:11px;color:#10b981;margin-top:8px;}
  .co-paw{font-size:50px;filter:drop-shadow(0 0 20px rgba(99,102,241,0.4));animation:float 3s ease-in-out infinite;}
  @keyframes float{0%,100%{transform:translateY(0)}50%{transform:translateY(-8px)}}
  @keyframes spin{to{transform:rotate(360deg)}}

  .co-card{background:rgba(255,255,255,0.025);border:1px solid rgba(255,255,255,0.07);
    border-radius:20px;padding:22px;margin-bottom:14px;backdrop-filter:blur(10px);animation:slideUp 0.5s ease;}
  .co-card-title{font-family:'Syne',sans-serif;font-size:14px;font-weight:700;color:#fff;margin-bottom:18px;display:flex;align-items:center;gap:8px;}
  .co-card-title span{background:rgba(99,102,241,0.15);color:#818cf8;padding:2px 10px;border-radius:20px;font-size:10px;letter-spacing:2px;}

  .co-tabs{display:grid;grid-template-columns:1fr 1fr 1fr;gap:7px;margin-bottom:18px;}
  .co-tab{padding:10px 6px;border-radius:12px;border:1.5px solid rgba(255,255,255,0.07);background:transparent;
    color:#6b7280;font-family:'DM Sans',sans-serif;font-size:12px;font-weight:600;cursor:pointer;
    transition:all 0.2s;display:flex;flex-direction:column;align-items:center;gap:3px;}
  .co-tab-icon{font-size:18px;}
  .co-tab:hover{border-color:rgba(99,102,241,0.3);color:#c7d2fe;}
  .co-tab.active{background:rgba(99,102,241,0.12);border-color:#6366f1;color:#a5b4fc;box-shadow:0 0 16px rgba(99,102,241,0.18);}

  /* UPI Apps */
  .co-upi-grid{display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:14px;}
  .co-upi-btn{padding:16px 10px;border-radius:14px;border:1.5px solid rgba(255,255,255,0.07);
    background:rgba(255,255,255,0.02);cursor:pointer;display:flex;flex-direction:column;
    align-items:center;gap:8px;transition:all 0.2s;position:relative;overflow:hidden;}
  .co-upi-btn:hover{transform:translateY(-2px);border-color:rgba(255,255,255,0.18);box-shadow:0 8px 24px rgba(0,0,0,0.3);}
  .co-upi-btn.sel{border-color:var(--ac);box-shadow:0 0 20px var(--glow);background:var(--bga);}
  .co-upi-icon{width:44px;height:44px;border-radius:12px;display:flex;align-items:center;justify-content:center;background:var(--bg);}
  .co-upi-name{font-size:11px;font-weight:600;color:#e5e7eb;}
  .co-tick{position:absolute;top:7px;right:7px;width:17px;height:17px;background:#10b981;border-radius:50%;
    display:flex;align-items:center;justify-content:center;font-size:9px;color:#fff;opacity:0;transition:opacity 0.2s;}
  .co-upi-btn.sel .co-tick{opacity:1;}
  .co-open-btn{width:100%;padding:15px;border-radius:13px;border:1.5px solid var(--ac);
    background:var(--bga);color:var(--ac);font-family:'Syne',sans-serif;font-size:14px;font-weight:700;
    cursor:pointer;transition:all 0.2s;margin-bottom:4px;}
  .co-open-btn:hover{transform:translateY(-2px);box-shadow:0 8px 24px var(--glow);}

  /* QR Tab */
  .co-qr-wrap{display:flex;flex-direction:column;align-items:center;padding:8px 0;}
  .co-qr-box{background:#fff;border-radius:20px;padding:20px;margin-bottom:16px;
    box-shadow:0 0 40px rgba(99,102,241,0.25);position:relative;}
  .co-qr-corner{position:absolute;width:20px;height:20px;border-color:#6366f1;border-style:solid;border-width:0;}
  .co-qr-tl{top:8px;left:8px;border-top-width:3px;border-left-width:3px;border-radius:4px 0 0 0;}
  .co-qr-tr{top:8px;right:8px;border-top-width:3px;border-right-width:3px;border-radius:0 4px 0 0;}
  .co-qr-bl{bottom:8px;left:8px;border-bottom-width:3px;border-left-width:3px;border-radius:0 0 0 4px;}
  .co-qr-br{bottom:8px;right:8px;border-bottom-width:3px;border-right-width:3px;border-radius:0 0 4px 0;}
  .co-qr-label{font-family:'Syne',sans-serif;font-size:13px;font-weight:700;color:#fff;margin-bottom:4px;text-align:center;}
  .co-qr-sub{font-size:11px;color:#4b5563;text-align:center;margin-bottom:16px;}
  .co-qr-apps{display:flex;gap:10px;justify-content:center;margin-bottom:16px;flex-wrap:wrap;}
  .co-qr-app{display:flex;flex-direction:column;align-items:center;gap:3px;font-size:10px;color:#6b7280;}
  .co-qr-app-icon{width:34px;height:34px;border-radius:10px;display:flex;align-items:center;justify-content:center;font-size:13px;font-weight:800;}
  .co-qr-upi{font-size:11px;color:#818cf8;background:rgba(99,102,241,0.1);border:1px solid rgba(99,102,241,0.2);
    border-radius:8px;padding:8px 14px;margin-bottom:14px;word-break:break-all;text-align:center;}
  .co-qr-confirm{width:100%;padding:14px;border-radius:13px;border:none;
    background:linear-gradient(135deg,#10b981,#059669);color:#fff;
    font-family:'Syne',sans-serif;font-size:14px;font-weight:700;cursor:pointer;transition:all 0.2s;}
  .co-qr-confirm:hover{transform:translateY(-2px);box-shadow:0 8px 24px rgba(16,185,129,0.35);}

  /* Common */
  .co-or{text-align:center;color:#374151;font-size:11px;margin:14px 0;letter-spacing:2px;text-transform:uppercase;position:relative;}
  .co-or::before,.co-or::after{content:'';position:absolute;top:50%;width:42%;height:1px;background:rgba(255,255,255,0.06);}
  .co-or::before{left:0;}.co-or::after{right:0;}
  .co-input{width:100%;padding:13px 16px;background:rgba(255,255,255,0.04);border:1.5px solid rgba(255,255,255,0.08);
    border-radius:12px;color:#fff;font-family:'DM Sans',sans-serif;font-size:14px;outline:none;transition:all 0.2s;box-sizing:border-box;}
  .co-input::placeholder{color:#374151;}
  .co-input:focus{border-color:#6366f1;box-shadow:0 0 0 3px rgba(99,102,241,0.12);background:rgba(99,102,241,0.04);}
  .co-input-hint{font-size:11px;color:#374151;margin-top:5px;}
  .co-pay-btn{width:100%;padding:17px;border-radius:13px;border:none;
    background:linear-gradient(135deg,#6366f1 0%,#4f46e5 100%);color:#fff;font-family:'Syne',sans-serif;
    font-size:16px;font-weight:800;cursor:pointer;transition:all 0.2s;letter-spacing:0.5px;
    box-shadow:0 8px 30px rgba(99,102,241,0.35);margin-top:8px;position:relative;overflow:hidden;}
  .co-pay-btn:hover:not(:disabled){transform:translateY(-2px);box-shadow:0 12px 40px rgba(99,102,241,0.5);}
  .co-pay-btn:disabled{opacity:0.6;cursor:not-allowed;}
  .co-pay-btn::after{content:'';position:absolute;inset:0;background:linear-gradient(90deg,transparent,rgba(255,255,255,0.08),transparent);transform:translateX(-100%);transition:transform 0.6s;}
  .co-pay-btn:hover::after{transform:translateX(100%);}
  .co-method-grid{display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:18px;}
  .co-mbox{padding:14px;background:rgba(255,255,255,0.02);border:1px solid rgba(255,255,255,0.07);border-radius:12px;text-align:center;}
  .co-micon{font-size:22px;margin-bottom:4px;}
  .co-mname{font-size:12px;font-weight:600;color:#e5e7eb;}
  .co-msub{font-size:10px;color:#4b5563;margin-top:2px;line-height:1.4;}
  .co-sec{display:flex;gap:7px;justify-content:center;flex-wrap:wrap;margin:16px 0 10px;}
  .co-badge{padding:4px 11px;border-radius:20px;font-size:10px;font-weight:600;
    background:rgba(16,185,129,0.08);color:#10b981;border:1px solid rgba(16,185,129,0.18);letter-spacing:0.5px;}
  .co-powered{text-align:center;font-size:11px;color:#1f2937;}
  .co-back{display:block;width:100%;background:none;border:none;color:#374151;font-size:12px;
    cursor:pointer;text-align:center;padding:12px;font-family:'DM Sans',sans-serif;letter-spacing:1px;}
  .co-back:hover{color:#6b7280;}

  /* Success */
  .co-success-wrap{text-align:center;padding:52px 24px;animation:popIn 0.5s cubic-bezier(0.34,1.56,0.64,1);}
  @keyframes popIn{0%{transform:scale(0.8);opacity:0}100%{transform:scale(1);opacity:1}}
  .co-s-emoji{font-size:72px;display:block;margin-bottom:14px;animation:float 2s ease-in-out infinite;}
  .co-s-title{font-family:'Syne',sans-serif;font-size:26px;font-weight:800;color:#10b981;margin-bottom:6px;}
  .co-s-amt{font-size:15px;color:#6b7280;margin-bottom:22px;}
  .co-pid{background:rgba(16,185,129,0.08);border:1px solid rgba(16,185,129,0.18);border-radius:10px;
    padding:11px 14px;margin-bottom:22px;font-size:11px;color:#10b981;word-break:break-all;}
  .co-btn-row{display:flex;gap:10px;justify-content:center;flex-wrap:wrap;}
  .co-gbtn{padding:12px 22px;background:#10b981;color:#fff;border:none;border-radius:10px;
    font-family:'Syne',sans-serif;font-weight:700;font-size:14px;cursor:pointer;transition:all 0.2s;}
  .co-obtn{padding:12px 22px;background:transparent;color:#818cf8;border:1.5px solid rgba(99,102,241,0.3);
    border-radius:10px;font-family:'Syne',sans-serif;font-weight:700;font-size:14px;cursor:pointer;transition:all 0.2s;}
  .co-gbtn:hover{transform:translateY(-2px);box-shadow:0 8px 20px rgba(16,185,129,0.3);}
  .co-obtn:hover{background:rgba(99,102,241,0.08);border-color:#6366f1;transform:translateY(-2px);}

  .co-toast{position:fixed;bottom:24px;left:50%;transform:translateX(-50%) translateY(100px);
    background:#111827;border:1px solid rgba(99,102,241,0.25);border-radius:12px;padding:11px 20px;
    color:#e5e7eb;font-size:13px;font-weight:500;box-shadow:0 8px 32px rgba(0,0,0,0.6);
    z-index:9999;transition:transform 0.3s ease;white-space:nowrap;}
  .co-toast.show{transform:translateX(-50%) translateY(0);}
  @keyframes slideUp{from{opacity:0;transform:translateY(16px)}to{opacity:1;transform:translateY(0)}}
`;

// ─── Main Component ───────────────────────────────────────────
export default function Checkout() {
  const [tab, setTab]               = useState("upi");
  const [selectedApp, setSelectedApp] = useState(null);
  const [customUpi, setCustomUpi]   = useState("");
  const [loading, setLoading]       = useState(false);
  const [done, setDone]             = useState(false);
  const [paymentId, setPaymentId]   = useState("");
  const [toast, setToast]           = useState("");
  const [showToast, setShowToast]   = useState(false);
  const [qrConfirmed, setQrConfirmed] = useState(false);

  const amount    = parseInt(localStorage.getItem("item") || 0);
  const uid       = localStorage.getItem("id") || 0;
  const userName  = localStorage.getItem("uname") || "Customer";
  const userEmail = localStorage.getItem("email") || "customer@example.com";
  const navigate  = useNavigate();

  // UPI string for QR — standard BharatQR / UPI format
  const upiQrString = `upi://pay?pa=${MERCHANT_UPI}&pn=${encodeURIComponent(MERCHANT_NAME)}&am=${amount}&cu=INR&tn=${encodeURIComponent("Petology Order")}`;

  useEffect(() => {
    if (!localStorage.getItem("islogin")) { navigate("/login"); return; }
    const s = document.createElement("script");
    s.src = "https://checkout.razorpay.com/v1/checkout.js";
    document.body.appendChild(s);
  }, []);

  const msg = (text) => {
    setToast(text); setShowToast(true);
    setTimeout(() => setShowToast(false), 3200);
  };

  const clearCart = () =>
    fetch("http://localhost/Petshop/deletecart.php?uid=" + uid).catch(() => {});

  const saveOrder = (oid) =>
    axios({
      method: "POST", url: "http://localhost/Petshop/order.php",
      data: { pid: localStorage.getItem("pid") || 1, order_id: oid, uid, totalitem: localStorage.getItem("totalitem") || 1, amount },
      headers: { "Content-Type": "multipart/form-data" },
    }).catch(() => {});

  const success = (pid) => {
    setPaymentId(pid); saveOrder(pid); clearCart(); setDone(true); setLoading(false);
  };

  const handleRazorpay = () => {
    if (!window.Razorpay) { msg("⚠️ Page reload karein"); return; }
    setLoading(true);
    const rzp = new window.Razorpay({
      key: RAZORPAY_KEY_ID, amount: amount * 100, currency: "INR",
      name: MERCHANT_NAME, description: "Pet Purchase", image: "https://i.imgur.com/n5tjHFD.png",
      handler: (r) => success(r.razorpay_payment_id),
      prefill: { name: userName, email: userEmail },
      theme: { color: "#6366f1" },
      modal: { ondismiss: () => setLoading(false) },
    });
    rzp.on("payment.failed", (r) => { setLoading(false); msg("❌ " + r.error.description); });
    rzp.open();
  };

  const handleUpiApp = (app) => {
    const note = encodeURIComponent("Petology Order");
    msg(`Opening ${app.name}...`);
    window.location.href = app.getLink(MERCHANT_UPI, amount, note);
    setTimeout(() => success("UPI_" + Date.now()), 9000);
  };

  const handleCustomUpi = () => {
    if (!customUpi.includes("@")) { msg("⚠️ Valid UPI ID daalo (ex: name@upi)"); return; }
    window.location.href = `upi://pay?pa=${customUpi}&pn=${encodeURIComponent(MERCHANT_NAME)}&am=${amount}&cu=INR&tn=PetologyOrder`;
    msg("Opening UPI app...");
  };

  const handleQrConfirm = () => {
    const fakeId = "QR_" + Date.now();
    success(fakeId);
  };

  const selApp = UPI_APPS.find((a) => a.id === selectedApp);

  // ── SUCCESS SCREEN ────────────────────────────────────────
  if (done) return (
    <>
      <style>{css}</style>
      <div className="co-page"><div className="co-bg" /><Nav />
        <div className="co-wrap">
          <div className="co-card">
            <div className="co-success-wrap">
              <span className="co-s-emoji">🎉</span>
              <div className="co-s-title">Payment Successful!</div>
              <div className="co-s-amt">₹{amount.toLocaleString("en-IN")} paid successfully</div>
              <div className="co-pid"><strong>Payment ID:</strong> {paymentId}</div>
              <div className="co-btn-row">
                <button className="co-gbtn" onClick={() => navigate("/myorder")}>📦 My Orders</button>
                <button className="co-obtn" onClick={() => navigate("/product")}>🐾 Shop More</button>
              </div>
            </div>
          </div>
        </div>
      </div>
    </>
  );

  // ── MAIN CHECKOUT ─────────────────────────────────────────
  return (
    <>
      <style>{css}</style>
      <div className="co-page">
        <div className="co-bg" />
        <Nav />
        <div className="co-wrap">

          {/* Header */}
          <div className="co-header">
            <div className="co-logo">🐾 Petology</div>
            <h1 className="co-title">Secure Checkout</h1>
            <p className="co-sub">256-BIT SSL • RBI APPROVED • PCI DSS</p>
          </div>

          {/* Amount Card */}
          <div className="co-amount">
            <div>
              <div className="co-amt-label">Total Payable</div>
              <div className="co-amt-val"><em>₹</em>{amount.toLocaleString("en-IN")}</div>
              <div className="co-amt-free">✅ Free delivery included</div>
            </div>
            <div className="co-paw">🐶</div>
          </div>

          {/* Payment Card */}
          <div className="co-card">
            <div className="co-card-title">Payment Method <span>INSTANT</span></div>

            {/* 3 Tabs */}
            <div className="co-tabs">
              <button className={`co-tab ${tab === "upi" ? "active" : ""}`} onClick={() => setTab("upi")}>
                <span className="co-tab-icon">📲</span>UPI Apps
              </button>
              <button className={`co-tab ${tab === "qr" ? "active" : ""}`} onClick={() => setTab("qr")}>
                <span className="co-tab-icon">▣</span>QR Code
              </button>
              <button className={`co-tab ${tab === "card" ? "active" : ""}`} onClick={() => setTab("card")}>
                <span className="co-tab-icon">💳</span>Card/Bank
              </button>
            </div>

            {/* ══ UPI APPS TAB ══ */}
            {tab === "upi" && <>
              <div className="co-upi-grid">
                {UPI_APPS.map((app) => (
                  <button
                    key={app.id}
                    className={`co-upi-btn ${selectedApp === app.id ? "sel" : ""}`}
                    style={{ "--ac": app.color, "--glow": app.color + "33", "--bg": app.bg, "--bga": app.bg + "18" }}
                    onClick={() => setSelectedApp(app.id)}
                  >
                    <div className="co-upi-icon">
                      <span style={app.labelStyle}>{app.label}</span>
                    </div>
                    <span className="co-upi-name">{app.name}</span>
                    <div className="co-tick">✓</div>
                  </button>
                ))}
              </div>

              {selApp && (
                <button
                  className="co-open-btn"
                  style={{ "--ac": selApp.color, "--bga": selApp.bg + "18", "--glow": selApp.color + "33" }}
                  onClick={() => handleUpiApp(selApp)}
                >
                  Open {selApp.name} → Pay ₹{amount.toLocaleString("en-IN")}
                </button>
              )}

              <div className="co-or">or enter UPI ID manually</div>
              <input
                className="co-input"
                placeholder="yourname@okaxis  /  9876543210@upi"
                value={customUpi}
                onChange={(e) => setCustomUpi(e.target.value)}
              />
              <div className="co-input-hint">Works with GPay, PhonePe, Paytm, BHIM, any UPI app</div>
              {customUpi.includes("@") && (
                <button className="co-pay-btn" onClick={handleCustomUpi}>
                  💸 Pay ₹{amount.toLocaleString("en-IN")} via UPI ID
                </button>
              )}
            </>}

            {/* ══ QR CODE TAB ══ */}
            {tab === "qr" && (
              <div className="co-qr-wrap">
                <div className="co-qr-label">Scan & Pay — Any UPI App</div>
                <div className="co-qr-sub">Open any UPI app → Scan QR → Pay instantly</div>

                {/* Supported apps row */}
                <div className="co-qr-apps">
                  {[
                    { label: "G", style: { background: "linear-gradient(135deg,#4285F4,#34A853,#FBBC05,#EA4335)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent", fontWeight: 900 }, bg: "#e8f0fe", name: "GPay" },
                    { label: "Pe", style: { color: "#5f259f", fontWeight: 900 }, bg: "#f3e8ff", name: "PhonePe" },
                    { label: "PT", style: { color: "#00BAF2", fontWeight: 900 }, bg: "#e0f7fe", name: "Paytm" },
                    { label: "B", style: { color: "#e84141", fontWeight: 900 }, bg: "#fee2e2", name: "BHIM" },
                  ].map((a, i) => (
                    <div className="co-qr-app" key={i}>
                      <div className="co-qr-app-icon" style={{ background: a.bg }}>
                        <span style={a.style}>{a.label}</span>
                      </div>
                      <span>{a.name}</span>
                    </div>
                  ))}
                </div>

                {/* QR Box */}
                <div className="co-qr-box">
                  <div className="co-qr-corner co-qr-tl" />
                  <div className="co-qr-corner co-qr-tr" />
                  <div className="co-qr-corner co-qr-bl" />
                  <div className="co-qr-corner co-qr-br" />
                  <UpiQR upiString={upiQrString} size={220} />
                </div>

                {/* UPI ID display */}
                <div className="co-qr-upi">
                  Pay to: <strong>{MERCHANT_UPI}</strong><br />
                  Amount: <strong>₹{amount.toLocaleString("en-IN")}</strong>
                </div>

                {/* Steps */}
                <div style={{ width: "100%", marginBottom: 14 }}>
                  {[
                    "Open GPay / PhonePe / Paytm / BHIM",
                    "Tap 'Scan QR' or 'Pay by QR'",
                    "Scan this QR code",
                    "Amount auto-fills → Confirm payment",
                    "Tap 'I have paid' button below",
                  ].map((step, i) => (
                    <div key={i} style={{ display: "flex", alignItems: "flex-start", gap: 10, marginBottom: 8 }}>
                      <div style={{
                        minWidth: 22, height: 22, borderRadius: "50%",
                        background: "rgba(99,102,241,0.2)", border: "1px solid rgba(99,102,241,0.4)",
                        display: "flex", alignItems: "center", justifyContent: "center",
                        fontSize: 11, fontWeight: 700, color: "#818cf8", marginTop: 1,
                      }}>{i + 1}</div>
                      <span style={{ fontSize: 13, color: "#9ca3af", lineHeight: 1.5 }}>{step}</span>
                    </div>
                  ))}
                </div>

                {/* Confirm button */}
                <button className="co-qr-confirm" onClick={handleQrConfirm}>
                  ✅ I Have Paid — Confirm Order
                </button>
                <div style={{ fontSize: 10, color: "#374151", textAlign: "center", marginTop: 8 }}>
                  Click only after completing payment in your UPI app
                </div>
              </div>
            )}

            {/* ══ CARD / NET BANKING TAB ══ */}
            {tab === "card" && <>
              <div className="co-method-grid">
                {[
                  { icon: "💳", name: "Debit Card", sub: "Visa • Mastercard • RuPay" },
                  { icon: "🏦", name: "Net Banking", sub: "SBI • HDFC • ICICI • Axis" },
                  { icon: "🪙", name: "Credit Card", sub: "All major cards accepted" },
                  { icon: "👛", name: "Wallets", sub: "Paytm • Amazon Pay • Freecharge" },
                ].map((m, i) => (
                  <div className="co-mbox" key={i}>
                    <div className="co-micon">{m.icon}</div>
                    <div className="co-mname">{m.name}</div>
                    <div className="co-msub">{m.sub}</div>
                  </div>
                ))}
              </div>
              <button className="co-pay-btn" onClick={handleRazorpay} disabled={loading}>
                {loading ? "⏳ Opening payment window..." : `🔐 Pay ₹${amount.toLocaleString("en-IN")} Now`}
              </button>
            </>}

            {/* Security Badges */}
            <div className="co-sec">
              {["🔒 256-bit SSL", "✅ RBI Approved", "🛡️ PCI DSS Compliant"].map((b, i) => (
                <span className="co-badge" key={i}>{b}</span>
              ))}
            </div>
            <div className="co-powered">
              Powered by <strong style={{ color: "#6366f1" }}>Razorpay</strong> — India's #1 Payment Gateway
            </div>
          </div>

          <button className="co-back" onClick={() => navigate("/cart")}>← BACK TO CART</button>
        </div>

        <div className={`co-toast ${showToast ? "show" : ""}`}>{toast}</div>
      </div>
    </>
  );
}
